#include <stdio.h>
#include <stdlib.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int n; scanf("%d", &n);
        int *a = (int*)malloc((n+3)*sizeof(int));
        for (int i = 0; i < n; ++i) scanf("%d", &a[i]);
        // extra zeros for dp beyond the end
        a[n] = a[n+1] = a[n+2] = 0;
        long long *dp = (long long*)malloc((n+3)*sizeof(long long));
        dp[n] = dp[n+1] = dp[n+2] = 0;
        for (int i = n-1; i >= 0; --i) {
            long long mn = dp[i+1];
            if (dp[i+2] < mn) mn = dp[i+2];
            if (dp[i+3] < mn) mn = dp[i+3];
            dp[i] = a[i] + mn;
        }
        long long ans = dp[0];
        if (n > 1 && dp[1] < ans) ans = dp[1];
        if (n > 2 && dp[2] < ans) ans = dp[2];
        printf("%lld\n", ans);
        free(a);
        free(dp);
    }
    return 0;
}

